import sys

class Solution:
    def findPeak(self, nums: list[list[int]]) -> list[int]:
        m = len(nums)
        n = len(nums[0]) if m else 0
        for i in range(m):
            for j in range(n):
                val = nums[i][j]
                if i > 0 and nums[i-1][j] >= val:
                    continue
                if i + 1 < m and nums[i+1][j] >= val:
                    continue
                if j > 0 and nums[i][j-1] >= val:
                    continue
                if j + 1 < n and nums[i][j+1] >= val:
                    continue
                return [i, j]
        return [0, 0]

if __name__ == '__main__':
    data = list(map(int, sys.stdin.read().split()))
    if len(data) < 3:
        sys.exit(0)
    m, _ = data[0], data[1]
