#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> findPeak(vector<vector<int>>& nums) {
        int m = nums.size();
        int n = m ? nums[0].size() : 0;
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                int val = nums[i][j];
                if (i > 0 && nums[i-1][j] >= val) continue;
                if (i + 1 < m && nums[i+1][j] >= val) continue;
                if (j > 0 && nums[i][j-1] >= val) continue;
                if (j + 1 < n && nums[i][j+1] >= val) continue;
                return {i, j};
            }
        }
        return {0,0};
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    vector<int> all;
    int x;
    while (cin >> x) all.push_back(x);
    if (all.size() < 3) return 0;
    int m = all[0];
    // ignore second value
    int cols = all[2];
    size_t idx = 3;
    vector<vector<int>> nums(m, vector<int>(cols));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < cols; ++j) {
            if (idx < all.size()) nums[i][j] = all[idx++];
        }
    }
    Solution sol;
    vector<int> ans = sol.findPeak(nums);
    cout << ans[0] << " " << ans[1] << "\n";
    return 0;
}
